INSERT INTO
COMMUNITY_POST(
	POST_ID
	,MEMBER_ID
	,TITLE
	,CONTENT
	,HAS_FILES
	,CATEGORY
)VALUES(
	#{postId}
	,#{memberId}
	,#{title}
	,#{content}
	,#{hasFiles}
	,#{category}
)

INSERT INTO POST_FILES (
	FILES_ID
	,POST_ID
	,MEMBER_ID
	,URL
	,TYPE
	,FILE_SIZE
	,CREATED_AT
	,ORIGIN_NAME
	,CHANGE_NAME
)
SELECT FILES_ID_SEQ.NEXTVAL, A.* FROM (

		SELECT #{pf.postId}
			  ,#{pf.memberId}
			  ,#{pf.url}
			  ,#{pf.type}
			  ,#{pf.fileSize}
			  ,SYSDATE
			  ,#{pf.originName}
			  ,#{pf.changeName}
		FROM DUAL

) A

mapper.delete:
DELETE FROM POST_FILES
WHERE POST_ID = #{postId}
  AND FILES_ID IN

      #{id}

mapper.select:
SELECT COUNT(*)
FROM POST_FILES
WHERE POST_ID = #{postId}

