				,PARENT_REPLY_ID
				,CONTENT
				,GROUP_ID
				,DEPTH
				,STATUS
) VALUES ( #{replyId}
		  ,#{postId}
		  ,#{memberId}
		  ,

		  	NULL
		  	#{parentReplyId}

		  ,#{content}
		  ,

		  	#{groupId}
		  	#{replyId}

		  ,#{depth}
		  ,'Y'
)

